class Solution:
    def distanceTraveled(self, mainTank: int, additionalTank: int) -> int:
        distance = 0
        while mainTank > 0:
            # Determine how much fuel can be used in this chunk
            use = min(5, mainTank)
            distance += use * 10
            mainTank -= use

            # Check if we used 5 liters and if we can transfer fuel
            if use == 5 and additionalTank > 0:
                mainTank += 1
                additionalTank -= 1

        return distance
